output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?system ?systemLabel WHERE {
  VALUES ?system {
    wd:Q13168533 wd:Q1371512 wd:Q8730
  }
  ?system rdfs:label ?systemLabel .
  FILTER(LANG(?systemLabel) = "en")
}

